sections.code_example:
class MathHelper:
    pi = 3.14159

    @classmethod
    def circle_area(cls, r):
        return cls.pi * r * r

    @staticmethod
    def add(a, b):
        return a + b

print(MathHelper.circle_area(5))
print(MathHelper.add(3, 4))

